循环队列实现/* GluttonousSnake *//* created by mike meng @ 2020.10.3*  email: mml1106@126.com*/class Queue &#123;    field Array buffer;    field int capbility;    field int rear;    field int front;    field int length;    constructor Queue new(int size)&#123;        let capbility = size;        let front = 0;        let rear = 0;        let buffer = Memory.alloc(size);        let length = 0;        return this;    &#125;    method void dispose()&#123;        do buffer.dispose();         do Memory.deAlloc(this);        return;    &#125;    method boolean isEmpty()&#123;        return (rear = front);    &#125;    method int size()&#123;        return length;    &#125;    method boolean isFull()&#123;        var int check;        let check = Snake.mod(rear + 1,capbility);        return (check = front);    &#125;    method boolean push_back(int val)&#123;        /*check the Queue is Full*/        if(isFull())&#123;return false;&#125;        let length = length + 1;        let buffer[rear] = val;        let rear = Snake.mod(rear + 1,capbility);        return true;    &#125;    method boolean push_front(int val)&#123;        /*check the Queue is Full*/        if(isFull())&#123; return false;&#125;        let length = length + 1;        let front = Snake.mod(front - 1 + capbility,capbility);        let buffer[front] = val;        return true;    &#125;    method int pop_front()&#123;        var int res;        if(isEmpty())&#123;return -1;&#125;        let res = buffer[front];        let front = Snake.mod(front + 1,capbility);        let length = length - 1;        return res;    &#125;    method int pop_back()&#123;        var int res;        /*check the Queue is Full*/        if(isEmpty())&#123;return -1;&#125;        let length = length - 1;        let rear = Snake.mod(rear - 1 + capbility,capbility);        return buffer[rear];    &#125;    method void print()&#123;        var int curr;        var int data;        /*debug all elements of the queue*/        let curr = length;        while(~(curr = 0))&#123;            let data = pop_front();            do Output.printInt(data);            do Output.printChar(32); // prints a space            do push_back(data);            let curr = curr - 1;        &#125;        return;    &#125;&#125;
随机数生成器： 这个可以在维基百科上找到线性方法生成简单的随机数的原理/*Random Number GeneratorOriginal author: Taylor WackerModified by: Connor McKayThis is a pseudo random number generator that uses theLinear Congruential Generator (LCG) to generate randomnumbers.*/class Random &#123;	static int x;	/*	Sets a new seed value.	*/	function void seed(int seed) &#123;		let x = seed;		return;	&#125;	/*	Returns a mod b. b must be positive.	*/	function int mod(int a, int b) &#123;		if (a &lt; 0) &#123;			let a = -a;		&#125;		while ((a + 1) &gt; b) &#123;			let a = a - b;		&#125;		return a;	&#125;	/*	Returns the next random number. Can be negative or positive.	*/	function int next() &#123;		let x = Random.mod(7919 + (17*x),7919);		return x;	&#125;	/*	Returns a random value between x (inclusive) and y (non-inclusive).	y must be greater than x.	*/	function int between(int x, int y) &#123;		var int diff;		let diff = y - x;		return Random.mod(Random.next(), diff) + x;	&#125;&#125;
游戏的逻辑主体部分，不过写的过于复杂点了，其实还可以写的更简单一些，或者完成俄罗斯方块游戏之类的。/* GluttonousSnake *//* created by mike meng @ 2020.10.3*  email: mml1106@126.com*/class Snake &#123;   field int row;//   field int col;//width   field int bsize;//square size   field Array head; /*snake Queuehead*/   field Queue foods; /*current foods*/   field int foodCount; // food number count   field Queue body; // current snake body;   field int speed; //snake speed   field Array mask;// direction mask   field int direction; /*-1: none, 0: up, 1: right, 2 : down, 3 : left*/   field int state;  //current state;   field int score;  //current score;   /** Constructs a new square with a given location and size. */   constructor Snake new(int w,int h)&#123;      var int i;      var int val;      /*matrix height &amp; width*/      let row = h;      let col = w;      let bsize = 16;      /*game state: 0: runing, 1: game over*/      let state = 0;      /*snake head*/      let head = Array.new(2);      let head[0] = 0;      let head[1] = 0;      do drawBlock(0,0);      /*snake foods*/      let foods = Queue.new(100);      let i = 20;      do Random.seed(1);      while(~(i = 0))&#123;         let val = Snake.mod(Random.next(),row*col);         do foods.push_back(val);         //do Snake.debug(val);         do drawFood(val);         let i = i - 1;      &#125;            /*snake body*/      let body = Queue.new(row*col);      do body.push_back(0);      /*snake direction*/      /*-1: none, 0: up, 1: right, 2 : down, 3 : left*/      let mask = Array.new(5);      let direction = 1;      let mask[0] = -1;      let mask[1] =  0;      let mask[2] =  1;      let mask[3] =  0;      let mask[4] = -1;       /*snake score*/      let score = 0;      return this;   &#125;   /** Disposes this square. */   method void dispose() &#123;      do head.dispose();      do foods.dispose();      do body.dispose();      do mask.dispose();      do Memory.deAlloc(this);      return;   &#125;   /*math  mod function*/   function int mod(int m,int n)&#123;      return (m - ((m/n)*n));   &#125;   /** game is over**/   method boolean isOver()&#123;      return state = 1;   &#125;   /** snake move up **/   method void moveUp() &#123;      if(direction = 2)&#123;return;&#125;      let direction = 0;      return;   &#125;      /** snake move down **/   method void moveDown() &#123;      if(direction = 0)&#123;return;&#125;      let direction = 2;      return;   &#125;   /** snake move left **/   method void moveLeft() &#123;      if(direction = 1)&#123;return;&#125;      let direction = 3;      return;   &#125;   /** snake move right **/   method void moveRight() &#123;      if(direction = 3)&#123;return;&#125;      let direction = 1;      return;   &#125;   /*draw a block*/   method void drawBlock(int rx,int cx)&#123;      do Screen.setColor(true);      do Screen.drawRectangle(cx*16,(rx+2)*16,cx*16 + 15,(rx+2)*16 + 15);      return;   &#125;   /*erase a block*/   method void eraseBlock(int location)&#123;      var int rx;      var int cx;      let rx = location/col;      let cx = Snake.mod(location,col);      do Screen.setColor(false);      do Screen.drawRectangle(cx*16,(rx+2)*16,cx*16 + 15,(rx+2)*16 + 15);      return;   &#125;   /*debug*/   function void debug(int x)&#123;      do Screen.setColor(true);      do Output.moveCursor(0,0);      do Output.printInt(x);      return;   &#125;   /*draw a food*/   method void drawFood(int location)&#123;      var int rx;      var int cx;      let rx = location/col;      let cx = Snake.mod(location,col);      do Screen.setColor(true);      do Screen.drawLine(cx*16,(rx+2)*16,cx*16 + 15,(rx+2)*16);      do Screen.drawLine(cx*16,(rx+2)*16,cx*16,(rx+2)*16 + 15);      do Screen.drawLine(cx*16,(rx+2)*16,cx*16 + 15,(rx+2)*16 + 15);      do Screen.drawLine(cx*16,(rx+2)*16 + 15,cx*16 + 15,(rx+2)*16 + 15);      do Screen.drawLine(cx*16+15,(rx+2)*16,cx*16 + 15,(rx+2)*16 + 15);      do Screen.drawLine(cx*16+15,(rx+2)*16,cx*16,(rx+2)*16 + 15);      return;   &#125;   /*draw snake head*/   method void drawHead(int rx,int cx)&#123;      do Screen.setColor(true);      do Screen.drawLine(cx*16,(rx+2)*16,cx*16 + 15,(rx+2)*16 + 15);      do Screen.drawLine(cx*16+15,(rx+2)*16,cx*16,(rx+2)*16 + 15);      return;   &#125;   /*snake move one step*/   method boolean move() &#123;      var int x;      var int y;      var int i;      var int val;      var int rx;      var int cx;      var boolean eat;      if(isOver())&#123; return false;&#125;      if(direction &lt; 0)&#123; return true;&#125;            /*get the current move location*/      let x = head[0] + mask[direction];      let y = head[1] + mask[direction + 1];      let i = 0;      /*check the snake will touch the edge*/      if((x &lt; 0)|(y &lt; 0)|(x = row)|(y = col))&#123;         let state = 1;         return false;      &#125;      /*check the snake will touch the body*/      let i = body.size();      while(~(i = 0))&#123;         let val = body.pop_front();         let i = i - 1;         let rx = val/col;         let cx = Snake.mod(val,col);         if((rx = x) &amp; (cx = y))&#123;            let state = 1;            return false;         &#125;         do body.push_back(val);      &#125;      if(isOver())&#123; return false;&#125;      /*check the snake touch the foods*/      let i = foods.size();      while(~(i = 0))&#123;         let i = i - 1;         let val = foods.pop_front();         let rx = val/col;         let cx = Snake.mod(val,col);         if((rx = x) &amp; (cx = y))&#123;            let eat = true;            let score = score + 1;         &#125;else&#123;            do foods.push_back(val);         &#125;      &#125;      /*move snake one step*/      let head[0] = x;      let head[1] = y;      do drawBlock(x,y);      do body.push_front(x*col + y);      if(~eat)&#123;         do eraseBlock(body.pop_back());      &#125;else&#123;         /*we can produce a random food for the snake*/         //do prodFood();      &#125;      return true;   &#125;   method int prodFood()&#123;      var boolean valid;      var int location;      var int val;      var int i;      let valid = false;      while(~valid)&#123;         let location = Snake.mod(Random.next(),row*col);         let i = body.size();         let valid = true;         while(~(i=0))&#123;            let val = body.pop_front();            do body.push_back(val);            if(val = location)&#123;               let valid = false;            &#125;         &#125;       &#125;      do drawFood(location);      do foods.push_back(location);      return location;   &#125;   /*get the game score*/   method int getScore()&#123;      return score;   &#125;&#125;
/* GluttonousSnake *//* created by mike meng @ 2020.10.3*  email: mml1106@126.com*/class SnakeGame &#123;   field Snake snake; // the square of this game   field int width; // the current score of the snake game.   field int height; // the current score of the snake game.   field int speed; // the current move speed of the snake game.   /** Constructs a new Square Game. */   constructor SnakeGame new(int w,int h) &#123;      let snake = Snake.new(w,h);      let speed = 1;  // initial state is no movement      return this;   &#125;   /** Disposes this game. */   method void dispose() &#123;      do snake.dispose();      do Memory.deAlloc(this);      return;   &#125;   /**speed up game**/   method void speedUp()&#123;      let speed = speed + 1;      return;   &#125;   /**speed down game**/   method void speedDown()&#123;      if(speed = 1) &#123;return;&#125;      let speed = speed - 1;      return;   &#125;   /** Moves the square in the current direction. */   method void moveSnake() &#123;      do snake.move();      do Sys.wait(5);  // delays the next movement      return;   &#125;   method void sleep(int seconds)&#123;      do Sys.wait(200/speed);      return;   &#125;   method void drawBackgroud()&#123;      do Screen.setColor(true);      do Screen.drawLine(0,0,0,255);      do Screen.drawLine(0,0,511,0);      do Screen.drawLine(511,0,511,255);      do Screen.drawLine(0,255,511,0255);      do Screen.drawLine(0,30,511,30);      return;   &#125;   method void drawText()&#123;      do Screen.setColor(true);      do Output.moveCursor(0,20);      do Output.printString(&quot;Your score is :&quot;);      do Output.printInt(snake.getScore());      if(snake.isOver())&#123;         do Output.moveCursor(1,24);         do Output.printString(&quot;Game Over!&quot;);      &#125;      return;   &#125;   /** Runs the game: handles the user&#x27;s inputs and moves the square accordingly */   method void run() &#123;      var char key;  // the key currently pressed by the user      var boolean exit;      let exit = false;      while (~exit) &#123;         // waits for a key to be pressed         do sleep(1);         do drawBackgroud();         do moveSnake();         do drawText();         let key = Keyboard.keyPressed();         if (key = 81)  &#123; let exit = true; &#125;     // q key         if (key = 43)  &#123; do speedUp();&#125;         // speed up         if (key = 45)  &#123; do speedDown();&#125;       // speed down         if (key = 131) &#123; do snake.moveUp();&#125;    // up arrow         if (key = 133) &#123; do snake.moveDown(); &#125;   // down arrow         if (key = 130) &#123; do snake.moveLeft(); &#125;   // left arrow         if (key = 132) &#123; do snake.moveRight(); &#125;   // right arrow     &#125; // while     return;   &#125;&#125;

lazy alloaction感觉这个lab是最近感觉最容易的lab了，只花了一天就完成了lab，还是感谢网络资源，感谢各位后浪们的付出，将课件翻译成中文版，翻译的质量很好，通过阅读lecture即可很快的熟悉相关的lazy allocation的原理描述，利用trap来实现。我们再来仔细看一下trap的原理：
中断现场-&gt;保存现场-&gt; 处理trap -&gt;恢复现场-&gt;恢复运行
利用trap我们可以进行相关的指令跳转，来执行我们需要的操作，执行完成之后，我们再恢复指令重新执行。所以我们可以利用trap来进行lazy allocation.按需申请物理内存资源，我们在申请内存时，可以先对只对该虚拟地址va进行标记，如果实际的程序需要进行访问该va时，我们再申请实际的物理内存页进行映射，映射完成后我们再恢复指令运行。git repo
Eliminate allocation from sbrkYour first task is to delete page allocation from the sbrk(n) system call implementation, which is the function sys_sbrk() in sysproc.c. The sbrk(n) system call grows the process&#x27;s memory size by n bytes, and then returns the start of the newly allocated region (i.e., the old size). Your new sbrk(n) should just increment the process&#x27;s size (myproc()-&gt;sz) by n and return the old size. It should not allocate memory -- so you should delete the call to growproc() (but you still need to increase the process&#x27;s size!).
这个非常容易实现，我们只需要在sys_sbrk函数内部对地址进行标记，标记该进程已经拥有该地址空间即可。我们可以仔细分析一下内存我们可以看到代码实现如下：
uint64sys_sbrk(void)&#123;  uint64 addr;  int n;  struct proc * p = myproc();  if(argint(0, &amp;n) &lt; 0)    return -1;  addr = p-&gt;sz;  if(n &gt; 0)&#123;  	if(p-&gt;sz + n &gt; MAXVA) return -1;  	p-&gt;sz += n;  &#125;else&#123;	if(growproc(n) &lt; 0)		return -1;  &#125;    return addr;&#125;
Lazy allocationModify the code in trap.c to respond to a page fault from user space by mapping a newly-allocated page of physical memory at the faulting address, and then returning back to user space to let the process continue executing. You should add your code just before the printf call that produced the &quot;usertrap(): ...&quot; message. Modify whatever other xv6 kernel code you need to in order to get echo hi to work.

实现在发生trap时我们时，我们首先判断发生trap时的地址是否合法，如果合法则我们认为该内存是lazy allocation，此时我们就kalloc一页实际的物理内存，然后进行映射，映射完成后，我们将trap恢复时执行的指令地址设置为$sepc$寄存器中的地址，CPU会从再次从发生trap的指令处开始执行。usertrap(void)&#123;  int which_dev = 0;  if((r_sstatus() &amp; SSTATUS_SPP) != 0)    panic(&quot;usertrap: not from user mode&quot;);  // send interrupts and exceptions to kerneltrap(),  // since we&#x27;re now in the kernel.  w_stvec((uint64)kernelvec);  struct proc *p = myproc();    // save user program counter.  p-&gt;trapframe-&gt;epc = r_sepc();    if(r_scause() == 8)&#123;    // system call    if(p-&gt;killed)      exit(-1);    // sepc points to the ecall instruction,    // but we want to return to the next instruction.    p-&gt;trapframe-&gt;epc += 4;    // an interrupt will change sstatus &amp;c registers,    // so don&#x27;t enable until done with those registers.    intr_on();    syscall();  &#125; else if((which_dev = devintr()) != 0)&#123;    // ok  &#125; else &#123;    uint64 pcode = r_scause();	uint64 va = r_stval();	uint64 epc = r_sepc();		// page fault, valid virtual address, 记录trap发生的原因  	if(pcode == 15 || pcode == 13)&#123;		if(va &gt;= p-&gt;sz || va &lt;= p-&gt;trapframe-&gt;sp || va &gt; MAXVA)&#123;			p-&gt;killed = 1;			goto fail;		&#125;		// alloc a page		char *mem = kalloc();			    if(mem == 0)&#123;	        p-&gt;killed = 1;			goto fail;	    &#125;		memset(mem,0,PGSIZE);    // mapper a page for va		if(mappages(p-&gt;pagetable,PGROUNDDOWN(va),PGSIZE,(uint64)mem, PTE_W|PTE_X|PTE_R|PTE_U) != 0)&#123;			kfree(mem);			p-&gt;killed = 1;			goto fail;		&#125;    // restore epc		p-&gt;trapframe-&gt;epc = epc;  	&#125;else&#123;	    printf(&quot;usertrap(): unexpected scause %p pid=%d\n&quot;, r_scause(), p-&gt;pid);	    printf(&quot;            sepc=%p stval=%p\n&quot;, r_sepc(), r_stval());	    p-&gt;killed = 1;	&#125;  &#125;fail:  if(p-&gt;killed)    exit(-1);  // give up the CPU if this is a timer interrupt.  if(which_dev == 2)    yield();  usertrapret();&#125;
修改uvmunmap时，我们在页表中walk时一旦发现该virtual address无法找到对应的物理页时，则我们此时直接跳过，而不是直接panic。// Remove npages of mappings starting from va. va must be// page-aligned. The mappings must exist.// Optionally free the physical memory.voiduvmunmap(pagetable_t pagetable, uint64 va, uint64 npages, int do_free)&#123;  uint64 a;  pte_t *pte;  if((va % PGSIZE) != 0)    panic(&quot;uvmunmap: not aligned&quot;);  for(a = va; a &lt; va + npages*PGSIZE; a += PGSIZE)&#123;    // 未找到该地址    if((pte = walk(pagetable, a, 0)) == 0)&#123;	     continue;    &#125;		if((*pte &amp; PTE_V) == 0)&#123;      continue;	&#125;           if(PTE_FLAGS(*pte) == PTE_V)      panic(&quot;uvmunmap: not a leaf&quot;);    if(do_free)&#123;      uint64 pa = PTE2PA(*pte);      kfree((void*)pa);    &#125;    *pte = 0;  &#125;&#125;

Lazytests and UsertestsWe&#x27;ve supplied you with lazytests, an xv6 user program that tests some specific situations that may stress your lazy memory allocator. Modify your kernel code so that all of both lazytests and usertests pass.Handle negative sbrk() arguments.Kill a process if it page-faults on a virtual memory address higher than any allocated with sbrk().Handle the parent-to-child memory copy in fork() correctly.Handle the case in which a process passes a valid address from sbrk() to a system call such as read or write, but the memory for that address has not yet been allocated.Handle out-of-memory correctly: if kalloc() fails in the page fault handler, kill the current process.Handle faults on the invalid page below the user stack.

我们发现在进行usertests，sbrkarg这个测试结果一直过不了，页没有报usertrap的错误，仔细跟踪了一下代码，发现它是调用了sys_write操作，而sys_write最终调用了copyin的操作，仔细检查一下copyin的函数发现它是直接在页表中读取操作，walkaddr时报错，所以直接返回-1。所以我们需要修改walkaddr函数，我们发现当前的地址没有在页表中找到时，则取申请一页新的物理页，然后将其映射到新的物理地址中。uint64walkaddr(pagetable_t pagetable, uint64 va)&#123;  pte_t *pte;  uint64 pa;  if(va &gt;= MAXVA)    return 0;  pte = walk(pagetable, va, 0);  if(pte == 0)&#123;	return 0;  &#125;  if((*pte &amp; PTE_V) == 0)&#123;  	struct proc *p = myproc();	if(va &gt;= p-&gt;sz) return 0;	  // malloc a new page	char *mem = kalloc();	if(mem == 0) return 0;  // map a page for the new address	if(mappages(pagetable,PGROUNDDOWN(va),PGSIZE,(uint64)mem, PTE_W|PTE_X|PTE_R|PTE_U) != 0)&#123;		kfree(mem);		return 0;	&#125;		return (uint64)mem;  &#125;    if((*pte &amp; PTE_U) == 0)&#123;    return 0;  &#125;  pa = PTE2PA(*pte);  return pa;&#125;
我们最后还需要注意的提示：Handle faults on the invalid page below the user stack.
我们首先看一下系统用户进程的栈空间分布？我们知道在栈的空件是从高地址往低地址增长的，如果我们发现栈的空间大小一个page，栈的地址空间为1~4096,因为所有的进程都是用户初始化进程的子进程，在子进程复制时，同时会复制父进程的栈空间。我们在进行sbrk操作时，实际扩充的进程的heap.voiduserinit(void)&#123;  struct proc *p;  p = allocproc();  initproc = p;    // allocate one user page and copy init&#x27;s instructions  // and data into it.  uvminit(p-&gt;pagetable, initcode, sizeof(initcode));  p-&gt;sz = PGSIZE;  // prepare for the very first &quot;return&quot; from kernel to user.  p-&gt;trapframe-&gt;epc = 0;      // user program counter  p-&gt;trapframe-&gt;sp = PGSIZE;  // user stack pointer  safestrcpy(p-&gt;name, &quot;initcode&quot;, sizeof(p-&gt;name));  p-&gt;cwd = namei(&quot;/&quot;);  p-&gt;state = RUNNABLE;  release(&amp;p-&gt;lock);&#125;
Handle faults on the invalid page below the user stack.


user stack：user stack主要作为用户程序在userspace执行时需要的栈空间，当我们在用户空间执行用户的程序时，这时sp寄存器指向的就是user stack。
kernel stack：kernel stack主要用户进程在系统调用时，切换到内核时执行内核的系统函数时，则这时kernel space执行时需要的栈空间，当系统调用发生时，则会发生trap，此时系统会切换pc到内核的函数调用，则此时我们执行内核函数时所需要的栈即为kernel stack。我们可以看到kstack之间有一个guard page.  p-&gt;trapframe-&gt;kernel_sp = p-&gt;kstack + PGSIZE; // process&#x27;s kernel stack// map kernel stacks beneath the trampoline,// each surrounded by invalid guard pages.#define KSTACK(p) (TRAMPOLINE - ((p)+1)* 2*PGSIZE)
stack相邻的地方都有一个guard page，为了防止stack越界，访问guard page时就会报错。我们可以看到在exec函数执行时，代码和数据加装在完成后，会紧接着申请两个物理页，一个作为guard page,一个作为stack。当然方式比较奇怪：// Allocate two pages at the next page boundary.// Use the second as the user stack.sz = PGROUNDUP(sz);uint64 sz1;// malloc 2 pageif((sz1 = uvmalloc(pagetable, sz, sz + 2*PGSIZE)) == 0)  goto bad;sz = sz1;// 将第一个page标志位去掉uvmclear(pagetable, sz-2*PGSIZE);sp = sz;stackbase = sp - PGSIZE;
Handle faults on the invalid page below the user stack.我们只需要检测当前的va是否处在guard page中。我们知道guard page的地址范围为：stackbase = PGROUNDDOWN(p-&gt;trapframe-&gt;sp) \\stackbase - PGSIZE \le va \le stackbase

